import React, {
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import {
  ActivityIndicator,
  FlatList,
  Keyboard,
  Pressable,
  StyleSheet,
  Text,
  TextInput,
  View,
  type ViewStyle,
} from "react-native";
import type { ListRenderItem } from "@react-native/virtualized-lists";
import { resolveThemeTokenForNative } from "../../Factory/helpers/style";

/* ─── Event types (mirrors PrimeReact) ─────────────────── */

export interface AutoCompleteChangeEvent<T = any> {
  originalEvent?: any;
  value: T;
}

export interface AutoCompleteCompleteEvent {
  originalEvent?: any;
  query: string;
}

export interface AutoCompleteSelectEvent<T = any> {
  originalEvent?: any;
  value: T;
}

export interface AutoCompleteUnselectEvent<T = any> {
  originalEvent?: any;
  value: T;
}

export interface AutoCompleteDropdownClickEvent {
  originalEvent?: any;
  query: string;
}

export interface VirtualScrollerOptions {
  itemSize: number;
}

/* ─── Props ────────────────────────────────────────────── */

export interface AutoCompleteProps<T = any> {
  id?: string;
  name?: string;
  testID?: string;

  value?: T | T[] | null;
  suggestions?: T[];
  field?: string;

  completeMethod?: (e: AutoCompleteCompleteEvent) => void;
  delay?: number;
  minLength?: number;

  onChange?: (e: AutoCompleteChangeEvent<T>) => void;
  onSelect?: (e: AutoCompleteSelectEvent<T>) => void;
  onUnselect?: (e: AutoCompleteUnselectEvent<T>) => void;
  onClear?: (e: { originalEvent?: any }) => void;
  onBlur?: (e: any) => void;
  onFocus?: (e: any) => void;
  onShow?: () => void;
  onHide?: () => void;
  onDropdownClick?: (e: AutoCompleteDropdownClickEvent) => void;

  placeholder?: string;
  disabled?: boolean;
  readOnly?: boolean;
  autoFocus?: boolean;
  invalid?: boolean;
  loading?: boolean;
  variant?: "outlined" | "filled";

  dropdown?: boolean;
  dropdownMode?: "blank" | "current";

  multiple?: boolean;
  selectionLimit?: number;

  forceSelection?: boolean;

  emptyMessage?: string;
  showEmptyMessage?: boolean;

  scrollHeight?: number;
  autoHighlight?: boolean;

  itemTemplate?: (item: T, index: number) => React.ReactNode;
  selectedItemTemplate?: (item: T) => React.ReactNode;
  panelFooterTemplate?: () => React.ReactNode;

  optionGroupLabel?: string;
  optionGroupChildren?: string;
  optionGroupTemplate?: (group: any) => React.ReactNode;

  virtualScrollerOptions?: VirtualScrollerOptions;

  style?: ViewStyle;
  inputStyle?: ViewStyle;
  panelStyle?: ViewStyle;
}

/* ─── Helpers ──────────────────────────────────────────── */

const resolveLabel = (item: any, field?: string): string => {
  if (item == null) return "";
  if (!field) return String(item);
  return String(item[field] ?? "");
};

const t = resolveThemeTokenForNative;

/* ─── Component ────────────────────────────────────────── */

export default function AutoComplete<T = any>({
  value,
  suggestions = [],
  completeMethod,
  onChange,
  onSelect,
  onUnselect,
  onClear,
  onBlur,
  onFocus,
  onShow,
  onHide,
  onDropdownClick,

  placeholder,
  disabled,
  readOnly,
  autoFocus,
  invalid,
  loading,
  variant = "outlined",

  dropdown,
  dropdownMode = "blank",

  field,

  multiple,
  selectionLimit,
  forceSelection,

  delay = 300,
  minLength = 1,

  emptyMessage = "No results found",
  showEmptyMessage = false,

  scrollHeight = 200,
  autoHighlight,

  itemTemplate,
  selectedItemTemplate,
  panelFooterTemplate,

  optionGroupLabel,
  optionGroupChildren,
  optionGroupTemplate,

  virtualScrollerOptions,

  style,
  inputStyle,
  panelStyle,

  testID,
}: AutoCompleteProps<T>) {
  const inputRef = useRef<TextInput>(null);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const blurTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const [query, setQuery] = useState("");
  const [panelVisible, setPanelVisible] = useState(false);
  const [focused, setFocused] = useState(false);
  const [highlightedIndex, setHighlightedIndex] = useState(-1);

  // Keep latest callbacks in refs so selectItem never captures stale closures
  const onChangeRef = useRef(onChange);
  onChangeRef.current = onChange;
  const onSelectRef = useRef(onSelect);
  onSelectRef.current = onSelect;
  const onUnselectRef = useRef(onUnselect);
  onUnselectRef.current = onUnselect;
  const onShowRef = useRef(onShow);
  onShowRef.current = onShow;
  const onHideRef = useRef(onHide);
  onHideRef.current = onHide;


  const isFilled = variant === "filled";
  const isMultiple = !!multiple;

  const colors = useMemo(() => ({
    border: t("gray.300"),
    borderFocus: t("primary"),
    borderInvalid: t("red.500"),
    bg: isFilled ? t("gray.100") : (t("surface-card") || "#fff"),
    text: t("gray.800"),
    placeholder: t("gray.400"),
    itemBorder: t("gray.200"),
    itemHighlight: t("gray.100"),
    chipBg: t("indigo.100"),
    chipText: t("indigo.700"),
    chipRemove: t("indigo.500"),
    primary: t("primary"),
    emptyText: t("gray.400"),
    groupBg: t("gray.50"),
  }), [isFilled]);

  /* ─── Derived values ───────────────────────────────── */

  const selectedValues = useMemo<T[]>(() => {
    if (!isMultiple) return [];
    if (Array.isArray(value)) return value;
    return [];
  }, [value, isMultiple]);

  // Flatten groups for FlatList (same pattern as Core/Dropdown)
  const flatData = useMemo(() => {
    if (!optionGroupLabel || !optionGroupChildren) return suggestions;
    const out: any[] = [];
    suggestions.forEach((group: any) => {
      out.push({ __group: true, group });
      const children = group[optionGroupChildren];
      if (Array.isArray(children)) {
        children.forEach((child: any) => out.push(child));
      }
    });
    return out;
  }, [suggestions, optionGroupLabel, optionGroupChildren]);

  /* ─── Value sync ───────────────────────────────────── */

  useEffect(() => {
    if (!isMultiple && value != null) {
      const label = resolveLabel(value, field);
      setQuery(label);
    } else if (!isMultiple && value == null) {
      setQuery("");
    }
  }, [value, field, isMultiple]);

  /* ─── autoFocus ────────────────────────────────────── */

  useEffect(() => {
    if (autoFocus) {
      setTimeout(() => inputRef.current?.focus(), 100);
    }
  }, []);

  /* ─── autoHighlight ────────────────────────────────── */

  useEffect(() => {
    if (autoHighlight && flatData.length > 0 && panelVisible) {
      const firstNonGroup = flatData.findIndex((d: any) => !d.__group);
      setHighlightedIndex(firstNonGroup >= 0 ? firstNonGroup : 0);
    } else {
      setHighlightedIndex(-1);
    }
  }, [flatData, panelVisible, autoHighlight]);

  /* ─── Panel lifecycle ──────────────────────────────── */

  const showPanel = useCallback(() => {
    setPanelVisible((prev) => {
      if (!prev) onShowRef.current?.();
      return true;
    });
  }, []);

  const hidePanel = useCallback(() => {
    setPanelVisible((prev) => {
      if (prev) onHideRef.current?.();
      return false;
    });
  }, []);

  /* ─── Debounced search ─────────────────────────────── */

  const triggerSearch = useCallback(
    (text: string, event?: any) => {
      if (debounceRef.current) {
        clearTimeout(debounceRef.current);
      }
      if (text.length < minLength) {
        return;
      }

      debounceRef.current = setTimeout(() => {
        completeMethod?.({ originalEvent: event, query: text });
        showPanel();
      }, delay);
    },
    [completeMethod, delay, minLength, showPanel],
  );

  // Cleanup timers on unmount
  useEffect(() => {
    return () => {
      if (debounceRef.current) clearTimeout(debounceRef.current);
      if (blurTimeoutRef.current) clearTimeout(blurTimeoutRef.current);
    };
  }, []);

  /* ─── Text change ──────────────────────────────────── */

  const onTextChange = useCallback(
    (text: string) => {
      setQuery(text);

      if (text.length === 0) {
        hidePanel();
        if (!isMultiple) {
          onChangeRef.current?.({ originalEvent: undefined, value: null as any });
          onClear?.({ originalEvent: undefined });
        }
        return;
      }

      triggerSearch(text);
    },
    [hidePanel, isMultiple, onClear, triggerSearch],
  );

  /* ─── Selection ────────────────────────────────────── */

  const selectItem = useCallback(
    (item: T) => {

      // Cancel any pending blur handler
      if (blurTimeoutRef.current) {
        clearTimeout(blurTimeoutRef.current);
        blurTimeoutRef.current = null;
      }

      if (isMultiple) {
        if (selectionLimit && selectedValues.length >= selectionLimit) {
          return;
        }
        const isDuplicate = selectedValues.some(
          (v) => resolveLabel(v, field) === resolveLabel(item, field),
        );
        if (isDuplicate) {
          return;
        }

        const newValue = [...selectedValues, item];
        onChangeRef.current?.({ originalEvent: undefined, value: newValue as any });
        onSelectRef.current?.({ originalEvent: undefined, value: item });
        setQuery("");
      } else {
        const label = resolveLabel(item, field);
        onChangeRef.current?.({ originalEvent: undefined, value: item as any });
        onSelectRef.current?.({ originalEvent: undefined, value: item });
        setQuery(label);
        hidePanel();
        Keyboard.dismiss();
      }
    },
    [isMultiple, selectedValues, selectionLimit, field, hidePanel],
  );

  /* ─── Chip removal ─────────────────────────────────── */

  const removeChip = useCallback(
    (item: T, index: number) => {
      const newValues = selectedValues.filter((_, i) => i !== index);
      onChangeRef.current?.({ originalEvent: undefined, value: newValues as any });
      onUnselectRef.current?.({ originalEvent: undefined, value: item });
    },
    [selectedValues],
  );

  /* ─── Dropdown button ──────────────────────────────── */

  const onDropdownPress = useCallback(() => {
    if (disabled || readOnly) return;
    const q = dropdownMode === "current" ? query : "";
    onDropdownClick?.({ originalEvent: undefined, query: q });
    completeMethod?.({ originalEvent: undefined, query: q });
    setPanelVisible((prev) => {
      if (prev) {
        onHideRef.current?.();
        return false;
      }
      onShowRef.current?.();
      return true;
    });
    inputRef.current?.focus();
  }, [disabled, readOnly, dropdownMode, query, onDropdownClick, completeMethod]);

  /* ─── Focus / Blur ─────────────────────────────────── */

  const handleFocus = useCallback(
    (e: any) => {
      setFocused(true);
      onFocus?.(e);
    },
    [onFocus],
  );

  // Keep mutable refs for values used inside blur timeout to avoid stale closures
  const queryRef = useRef(query);
  queryRef.current = query;
  const suggestionsRef = useRef(suggestions);
  suggestionsRef.current = suggestions;

  const handleBlur = useCallback(
    (e: any) => {
      setFocused(false);

      // Delay to allow selectItem to fire first when tapping a suggestion
      blurTimeoutRef.current = setTimeout(() => {
        if (forceSelection && queryRef.current && !isMultiple) {
          const match = suggestionsRef.current.some(
            (s) => resolveLabel(s, field).toLowerCase() === queryRef.current.toLowerCase(),
          );
          if (!match) {
            setQuery("");
            onChangeRef.current?.({ originalEvent: e, value: null as any });
          }
        }
        hidePanel();
        onBlur?.(e);
      }, 200);
    },
    [forceSelection, isMultiple, field, hidePanel, onBlur],
  );

  /* ─── Render item ──────────────────────────────────── */

  const renderItem: ListRenderItem<any> = useCallback(
    ({ item, index }): React.ReactElement | null => {
      if (!item) return null;

      // Group header
      if (item.__group) {
        if (optionGroupTemplate) {
          return <>{optionGroupTemplate(item.group)}</>;
        }
        return (
          <View style={[styles.groupLabel, { backgroundColor: colors.groupBg }]}>
            <Text style={styles.groupLabelText}>
              {optionGroupLabel ? item.group?.[optionGroupLabel] : ""}
            </Text>
          </View>
        );
      }

      const isHighlighted = index === highlightedIndex;
      const isLast = index === flatData.length - 1;

      if (itemTemplate) {
        const rendered = itemTemplate(item, index);
        return rendered ? (
          <Pressable onPress={() => {
            selectItem(item);
          }}>{rendered}</Pressable>
        ) : null;
      }

      return (
        <Pressable
          onPress={() => {
            selectItem(item);
          }}
          style={[
            styles.option,
            !isLast && { borderBottomWidth: 1, borderBottomColor: colors.itemBorder },
            isHighlighted && { backgroundColor: colors.itemHighlight },
          ]}
        >
          <Text style={[styles.optionText, { color: colors.text }]}>
            {resolveLabel(item, field)}
          </Text>
        </Pressable>
      );
    },
    [
      flatData.length,
      highlightedIndex,
      itemTemplate,
      optionGroupTemplate,
      optionGroupLabel,
      field,
      selectItem,
      colors,
    ],
  );

  /* ─── Render ───────────────────────────────────────── */

  const borderColor = invalid
    ? colors.borderInvalid
    : focused
      ? colors.borderFocus
      : colors.border;

  const showPanelContent = panelVisible && (flatData.length > 0 || showEmptyMessage || !!emptyMessage);

  return (
    <View style={[styles.container, style]} testID={testID}>
      <View
        style={[
          styles.inputWrapper,
          {
            borderColor,
            backgroundColor: colors.bg,
            borderWidth: isFilled ? 0 : 1,
          },
          isMultiple && styles.inputWrapperMultiple,
          disabled && styles.disabled,
          inputStyle,
        ]}
      >
        {/* Chips (multiple mode) */}
        {isMultiple && selectedValues.length > 0 && (
          <View style={styles.chipContainer}>
            {selectedValues.map((item, i) =>
              selectedItemTemplate ? (
                <View key={i}>{selectedItemTemplate(item)}</View>
              ) : (
                <View key={i} style={[styles.chip, { backgroundColor: colors.chipBg }]}>
                  <Text style={[styles.chipText, { color: colors.chipText }]}>
                    {resolveLabel(item, field)}
                  </Text>
                  {!disabled && !readOnly && (
                    <Pressable
                      onPress={() => removeChip(item, i)}
                      hitSlop={{ top: 8, bottom: 8, left: 8, right: 8 }}
                    >
                      <Text style={[styles.chipRemove, { color: colors.chipRemove }]}>✕</Text>
                    </Pressable>
                  )}
                </View>
              ),
            )}
          </View>
        )}

        {/* Text input */}
        <TextInput
          ref={inputRef}
          editable={!disabled && !readOnly}
          value={query}
          placeholder={placeholder}
          placeholderTextColor={colors.placeholder}
          onChangeText={onTextChange}
          onFocus={handleFocus}
          onBlur={handleBlur}
          style={[styles.inputField, { color: colors.text }]}
        />

        {/* Loading indicator */}
        {loading && (
          <ActivityIndicator
            size="small"
            color={colors.primary}
            style={styles.loadingIndicator}
          />
        )}

        {/* Dropdown button */}
        {dropdown && (
          <Pressable
            onPress={onDropdownPress}
            style={styles.dropdownBtn}
            disabled={disabled || readOnly}
          >
            <Text style={{ color: colors.placeholder }}>▾</Text>
          </Pressable>
        )}
      </View>

      {/* Suggestions panel */}
      {showPanelContent && (
        <View
          style={[
            styles.panel,
            { borderColor: colors.border, backgroundColor: colors.bg, maxHeight: scrollHeight },
            panelStyle,
          ]}
        >
          {flatData.length > 0 ? (
            <FlatList
              data={flatData}
              keyExtractor={(_, i) => String(i)}
              renderItem={renderItem}
              extraData={selectItem}
              keyboardShouldPersistTaps="handled"
              getItemLayout={
                virtualScrollerOptions
                  ? (_, index) => ({
                      length: virtualScrollerOptions.itemSize,
                      offset: virtualScrollerOptions.itemSize * index,
                      index,
                    })
                  : undefined
              }
            />
          ) : (
            <View style={styles.emptyContainer}>
              <Text style={[styles.emptyText, { color: colors.emptyText }]}>
                {emptyMessage}
              </Text>
            </View>
          )}
          {panelFooterTemplate?.()}
        </View>
      )}
    </View>
  );
}

/* ─── Styles ─────────────────────────────────────────── */

const styles = StyleSheet.create({
  container: {
    width: "100%",
    position: "relative",
  },
  inputWrapper: {
    flexDirection: "row",
    alignItems: "center",
    borderRadius: 6,
    paddingHorizontal: 8,
    minHeight: 42,
  },
  inputWrapperMultiple: {
    flexWrap: "wrap",
    paddingVertical: 4,
  },
  disabled: {
    opacity: 0.5,
  },
  inputField: {
    flex: 1,
    fontSize: 14,
    paddingVertical: 8,
    minWidth: 80,
  },
  loadingIndicator: {
    marginRight: 8,
  },
  dropdownBtn: {
    paddingHorizontal: 8,
    paddingVertical: 4,
  },
  chipContainer: {
    flexDirection: "row",
    flexWrap: "wrap",
    gap: 4,
    marginRight: 4,
  },
  chip: {
    flexDirection: "row",
    alignItems: "center",
    paddingLeft: 10,
    paddingRight: 6,
    paddingVertical: 3,
    borderRadius: 16,
    gap: 4,
  },
  chipText: {
    fontSize: 13,
  },
  chipRemove: {
    fontSize: 12,
    paddingHorizontal: 2,
  },
  panel: {
    position: "absolute",
    top: "100%",
    left: 0,
    right: 0,
    marginTop: 4,
    borderWidth: 1,
    borderRadius: 6,
    zIndex: 1000,
    shadowColor: "#000",
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.1,
    shadowRadius: 4,
    elevation: 4,
    overflow: "hidden",
  },
  option: {
    paddingHorizontal: 12,
    paddingVertical: 10,
  },
  optionText: {
    fontSize: 14,
  },
  groupLabel: {
    paddingHorizontal: 12,
    paddingVertical: 8,
  },
  groupLabelText: {
    fontSize: 12,
    fontWeight: "700",
    textTransform: "uppercase",
    letterSpacing: 0.5,
  },
  emptyContainer: {
    padding: 16,
    alignItems: "center",
  },
  emptyText: {
    fontSize: 14,
  },
});
